// Code generated by selo gen --lang rust. DO NOT EDIT.

use crate::mod11::{self, CheckDigit, Rule, SeloError};

const DV: CheckDigit = CheckDigit { weights: &[2, 3, 4, 5, 6, 7, 8, 9], rule: Rule::ModRemainder, remainder_to0: &[0, 1], multiply_by10: false, encode_x_at: 0, encode_zero_at: 0 };

const ALPHANUM: &[u8] = b"0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";

/// Uppercase and keep only [0-9A-Z], capped at 14 chars.
fn clean(value: &str) -> String {
    let mut out = String::with_capacity(14);
    for ch in value.bytes() {
        let up = ch.to_ascii_uppercase();
        if up.is_ascii_digit() || up.is_ascii_uppercase() {
            out.push(up as char);
            if out.len() == 14 {
                break;
            }
        }
    }
    out
}

/// Compute one check digit over the base string (RL-cycling weights).
fn dv(base: &str) -> i32 {
    let vals: Vec<i32> = base.bytes().map(mod11::char_value).collect();
    mod11::compute_digit(mod11::weighted_sum(&vals, DV.weights, true), &DV)
}

/// Report whether value is a valid alphanumeric CNPJ.
pub fn validate_cnpj(value: &str) -> bool {
    let c = clean(value);
    if c.len() != 14 {
        return false;
    }
    if mod11::all_equal(&c) {
        return false;
    }
    let bytes = c.as_bytes();
    if !bytes[12].is_ascii_digit() {
        return false;
    }
    if !bytes[13].is_ascii_digit() {
        return false;
    }
    let base = &c[0..12];
    let dv1 = dv(base);
    let dv2 = dv(&format!("{}{}", base, dv1));
    dv1 == (bytes[12] - b'0') as i32 && dv2 == (bytes[13] - b'0') as i32
}

/// Render value as XX.XXX.XXX/XXXX-XX, or return an error on bad length.
pub fn format_cnpj(value: &str) -> Result<String, SeloError> {
    let c = clean(value);
    if c.len() != 14 {
        return Err(SeloError::InvalidLength);
    }
    Ok(format!("{}.{}.{}/{}-{}", &c[0..2], &c[2..5], &c[5..8], &c[8..12], &c[12..14]))
}

/// Return a random, valid alphanumeric CNPJ (14 chars, unformatted).
pub fn generate_cnpj() -> String {
    let mut base = String::with_capacity(12);
    for _ in 0..12 {
        base.push(ALPHANUM[mod11::rand_int(ALPHANUM.len() as u64 - 1) as usize] as char);
    }
    let dv1 = dv(&base);
    let dv2 = dv(&format!("{}{}", base, dv1));
    format!("{}{}{}", base, dv1, dv2)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn vector() -> serde_json::Value {
        let p = concat!(env!("CARGO_MANIFEST_DIR"), "/vectors/cnpj.json");
        let s = std::fs::read_to_string(p).expect("read vector");
        serde_json::from_str(&s).expect("parse vector")
    }

    #[test]
    fn validate_cases() {
        for case in vector()["validate"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let valid = case["valid"].as_bool().unwrap();
            assert_eq!(valid, validate_cnpj(input), "validate {}", input);
        }
    }

    #[test]
    fn format_cases() {
        for case in vector()["format"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let is_error = case
                .get("error")
                .and_then(|e| e.as_str())
                .map(|e| !e.is_empty())
                .unwrap_or(false);
            if is_error {
                assert!(format_cnpj(input).is_err(), "format expected err {}", input);
            } else {
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, format_cnpj(input).unwrap(), "format {}", input);
            }
        }
    }

    #[test]
    fn generate_round_trip() {
        for _ in 0..100 {
            let v = generate_cnpj();
            assert!(validate_cnpj(&v), "generate produced invalid: {}", v);
        }
    }
}
